"use client";

import * as React from "react";
import {
  motion,
  type MotionValue,
  useReducedMotion,
  useTransform,
} from "motion/react";

import { cn } from "@/lib/utils";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";
import {
  type ProgressPlayback,
  useCommittedProgress,
} from "@/components/experience/use-committed-progress";

const subscribeToHydration = () => () => undefined;

function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

type ExpandingMediaProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  media: React.ReactNode;
  overlay?: React.ReactNode;
  overlayClassName?: string;
  playback?: ProgressPlayback;
  progress?: MotionValue<number>;
  range?: [number, number];
  scrollScreens?: number;
  scrimClassName?: string;
  stageClassName?: string;
  startInset?: string;
  resetKey?: React.Key;
};

/** Expands an image or video from an editorial frame into a full-viewport beat. */
export function ExpandingMedia({
  className,
  label,
  media,
  overlay,
  overlayClassName,
  playback = "scrub",
  progress: controlledProgress,
  range = [0.12, 0.72],
  scrollScreens = 2.5,
  scrimClassName = "bg-gradient-to-t from-black/70 via-black/10 to-transparent",
  stageClassName,
  startInset = "12% 10% 12% 10%",
  resetKey,
  style,
  ...props
}: ExpandingMediaProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const mounted = useHydrated();
  const reducedMotionPreference = useReducedMotion();
  const reducedMotion = mounted && Boolean(reducedMotionPreference);
  const localProgress = useElementScrollProgress(rootRef);
  const sourceProgress = controlledProgress ?? localProgress;
  const progress = useCommittedProgress(sourceProgress, playback, resetKey);
  const clipPath = useTransform(progress, range, [`inset(${startInset} round 2rem)`, "inset(0% 0% 0% 0% round 0rem)"], { clamp: true });
  const scale = useTransform(progress, range, [0.96, 1], { clamp: true });

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-expanding-media
      data-playback={playback}
      className={cn("relative isolate", className)}
      style={{ minHeight: reducedMotion ? "100svh" : `${Math.max(1.5, scrollScreens) * 100}svh`, ...style }}
      {...props}
    >
      <div className={cn(reducedMotion ? "relative min-h-svh" : "sticky top-0 h-svh overflow-hidden", stageClassName)}>
        <motion.div className="absolute inset-0 overflow-hidden will-change-[clip-path,transform]" style={reducedMotion ? undefined : { clipPath, scale }}>
          {media}
        </motion.div>
        {overlay ? (
          <div className={cn("pointer-events-none absolute inset-0 z-10", scrimClassName, overlayClassName)}>
            {overlay}
          </div>
        ) : null}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import {
  type MotionValue,
  useMotionValue,
  useMotionValueEvent,
} from "motion/react";

export type ProgressPlayback = "scrub" | "commit";

/**
 * Converts a reversible scroll MotionValue into a one-way progress value.
 * Use `resetKey` when a route, slide, or story chapter should deliberately
 * replay the effect.
 */
export function useCommittedProgress(
  source: MotionValue<number>,
  playback: ProgressPlayback = "scrub",
  resetKey?: React.Key,
) {
  const committed = useMotionValue(source.get());

  React.useEffect(() => {
    committed.set(source.get());
  }, [committed, resetKey, source]);

  useMotionValueEvent(source, "change", (value) => {
    committed.set(playback === "commit" ? Math.max(committed.get(), value) : value);
  });

  return playback === "commit" ? committed : source;
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` â†’ `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => {
        const rect = element.getBoundingClientRect();
        const travel = Math.max(1, element.offsetHeight - window.innerHeight);
        progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
      });
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    update();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}
